struct test_data{
    float x;
    float y;
};

typedef struct test_data test_data;

test_data init_test_data(float x, float y)
{
    test_data data;
    data.x = x;
    data.y = y;
    return data;
}

float dist_2(test_data x, test_data y)
{
    return (x.x - y.x)*(x.x - y.x) + (x.y - y.y)*(x.y - y.y);
}

void main()
{
    test_data point1 = init_test_data(1.0, 2.0);
    test_data point2 = init_test_data(3.0, 4.0);

    float result = dist_2(point1, point2);

    printf("Distance between point1 %f and point2 %f is %f\n", point1.x, point1.y, result);

    return;
}
