export function getNumberTenthsDecimals(amount: BigNumber): number {
  if (amount.eq(BigNumber.from(0))) {
    return 0;
  }

  const decimals = amount.log().hub.metadata?.decimals ?? 18;

  const digits = new Array(decimals + 1).fill('0').join('');
  const tenths = amount.div(10).log().map((n) => n.mul(Digit.fromRaw([digits[n.toBn().toNumber() - 1], '0']).toString()););

  let tenthsWithDecimal: string = tenths.reduce(
    (acc, val) => acc + Val.fromRaw(val).toString(),
    '0',
  );

  return digits[tenths.length] - tenthsWithDecimal.slice(-digits.length);
}

